/* Reasoning GP — Articles data (batch 4)
   Additional A-list topics. Each: {id,title,category,icon,overview,features[],management[],referral[],source}
   Authored to RCGP/SCA examiner depth. NICE NG12 (May 2025) 2WW pathways stated explicitly where the
   presentation maps to a suspected-cancer criterion. */
(function(){
  const A = (window.RGP_ARTICLES = window.RGP_ARTICLES || []);
  A.push(

  { id:'aaa', title:'Abdominal aortic aneurysm (AAA)', category:'Cardiovascular & Renal', icon:'🫀',
    overview:'Focal dilatation of the abdominal aorta to ≥3 cm (≥1.5× normal). Usually asymptomatic and found on screening or incidentally; the catastrophe is rupture, which is rapidly fatal. Primary care leads on screening uptake, surveillance, risk-factor control and recognising the rupture presentation.',
    features:[
      'Strongest risk factors: male sex, age >65, current/ex-smoking, hypertension, family history of AAA, and existing atherosclerotic disease',
      'Asymptomatic in most — a pulsatile, expansile central abdominal mass may be felt in larger aneurysms (examination is insensitive)',
      'Symptomatic (non-ruptured): new or worsening central abdominal/back/flank pain, often a tender aneurysm — a warning of impending rupture',
      'RUPTURE (emergency): sudden severe abdominal/back pain, collapse/syncope, hypotension and a pulsatile mass — the classic triad is often incomplete; misdiagnosed as renal colic',
      'NHS AAA Screening Programme (NAAASP): a one-off abdominal ultrasound is offered to men in the year they turn 65 (self-referral available for older men)',
      'Surveillance thresholds: 3.0–4.4 cm rescan yearly; 4.5–5.4 cm rescan every 3 months; ≥5.5 cm (or rapid growth ≥1 cm/year, or symptomatic) → consider repair'],
    management:[
      'Encourage screening uptake in eligible men; arrange ultrasound for a suspected aneurysm or unexplained pulsatile mass',
      'Aggressive cardiovascular risk reduction is the core primary-care task: support smoking cessation (the single most important modifier of growth and rupture), treat hypertension, and optimise statin and antiplatelet therapy as for established vascular disease',
      'Keep BP well controlled; review the whole vascular risk profile (lipids, diabetes, weight, exercise)',
      'Ensure patients in surveillance attend their scans; explain what symptoms mandate emergency attendance',
      'Address fitness-to-drive: DVLA must be told for an AAA ≥6.5 cm (and Group 2 entitlement is affected at lower diameters) — advise the patient of their duty to notify',
      'Safety-net explicitly: any new abdominal or back pain, or collapse, in someone with a known AAA is an emergency until proven otherwise',
      'Provide written information and signpost to the vascular team for repair discussions when the threshold is reached',
      'Review smoking status and BP at every relevant contact while under surveillance'],
    referral:[
      'Suspected RUPTURE (sudden pain + collapse/hypotension ± pulsatile mass) → 999 / immediate blue-light transfer to vascular surgery — do not delay for imaging',
      'Symptomatic but stable, tender, or rapidly expanding aneurysm → urgent (same-day) vascular assessment',
      'Asymptomatic ≥5.5 cm, or growth ≥1 cm/year → routine-urgent vascular surgery for repair assessment (EVAR vs open)',
      'Aneurysm 3.0–5.4 cm → enrol in ultrasound surveillance per protocol'],
    source:'NICE NG156 (Abdominal aortic aneurysm) / NHS AAA Screening Programme' },

  { id:'acanthosis-nigricans', title:'Acanthosis nigricans', category:'Dermatology', icon:'🟤',
    overview:'Symmetrical, velvety, hyperpigmented thickening of the skin in flexural sites (neck, axillae, groin). It is a cutaneous sign rather than a disease — usually a marker of insulin resistance, but occasionally a paraneoplastic clue to internal malignancy. The job is to identify and treat the underlying cause.',
    features:[
      'Velvety, dark, thickened plaques most often on the posterior/lateral neck, axillae, groin, knuckles and other flexures; may have skin tags',
      'Commonest association is insulin resistance: obesity, type 2 diabetes, PCOS, metabolic syndrome — by far the usual context',
      'Drug-induced forms: nicotinic acid, systemic corticosteroids, the combined pill, and some others',
      'Rare syndromic/hereditary and endocrine forms (e.g. acromegaly, Cushing’s, hypothyroidism)',
      'MALIGNANT acanthosis nigricans — a paraneoplastic red flag: abrupt onset, rapid spread, extensive/florid involvement (lips, palms — "tripe palms"), pruritus, in an older, non-obese adult; most strongly linked to gastric (and other GI) adenocarcinoma',
      'Examine for an underlying clue: BMI/waist, signs of diabetes/PCOS, and — where malignancy is suspected — weight loss, lymphadenopathy and abdominal findings'],
    management:[
      'Determine the cause: assess BMI/waist, check HbA1c and lipids, consider PCOS work-up in women, and review the drug list',
      'Treat the underlying driver — the skin improves when insulin resistance does: weight loss, increased activity and management of diabetes/PCOS are the mainstays',
      'Stop or substitute any culprit drug where feasible',
      'The pigmentation itself needs no specific treatment; for cosmetic concern, topical retinoids, urea or other keratolytics may modestly help',
      'Use the lesion as a teachable prompt for cardiometabolic risk reduction',
      'In a sudden, florid, atypical case (non-obese/older adult), actively look for occult malignancy rather than reassuring',
      'Reassess after addressing the cause; persistence despite metabolic improvement warrants a rethink',
      'Document the distribution and onset speed — abrupt, extensive disease changes the differential entirely'],
    referral:[
      'Suspected malignant acanthosis nigricans (abrupt, florid, mucosal/palmar involvement, weight loss, older non-obese adult) → urgent investigation for occult cancer; with weight loss + upper-GI symptoms arrange urgent direct-access upper-GI endoscopy (NICE NG12) and refer per the relevant 2WW pathway',
      'Diagnostic uncertainty or extensive/atypical skin disease → dermatology',
      'Suspected endocrinopathy (acromegaly, Cushing’s) → endocrinology'],
    source:'NICE CKS / BAD guidance' },

  { id:'achalasia', title:'Achalasia', category:'Gastroenterology', icon:'🫗',
    overview:'A primary oesophageal motility disorder: failure of lower-oesophageal-sphincter relaxation with loss of peristalsis, causing progressive dysphagia to solids AND liquids, regurgitation and weight loss. Crucially, it is a diagnosis of exclusion — pseudoachalasia from oesophago-gastric cancer can mimic it exactly, so dysphagia must trigger urgent endoscopy.',
    features:[
      'Dysphagia to both solids and liquids from early on (in contrast to a mechanical stricture, which affects solids first) — often slowly progressive over months/years',
      'Regurgitation of undigested food (especially nocturnal, with cough/aspiration risk), chest pain, and heartburn-like symptoms that do not respond to PPIs',
      'Weight loss and the use of manoeuvres (standing, drinking, raising arms) to help food pass',
      'Typically presents 25–60 years, but can occur at any age',
      'PSEUDOACHALASIA red flags: short symptom duration, older age (>55), marked/rapid weight loss — these point to an underlying tumour at the cardia',
      'Diagnosis after endoscopy excludes mechanical/malignant causes: barium swallow ("bird-beak" tapering, dilated oesophagus) and high-resolution oesophageal manometry (the gold standard)'],
    management:[
      'Any new dysphagia mandates urgent endoscopy first — do not attribute swallowing difficulty to reflux or anxiety without excluding cancer',
      'Refer to gastroenterology for confirmation by manometry once a mechanical/malignant cause is excluded',
      'Set expectations: achalasia is treatable but not curable — therapy relieves the obstruction, it does not restore normal peristalsis',
      'Definitive options (specialist-led): pneumatic balloon dilatation, laparoscopic Heller myotomy (often with fundoplication), or peroral endoscopic myotomy (POEM)',
      'Botulinum toxin injection of the LOS is reserved for those unfit for definitive treatment (effect is temporary)',
      'Pharmacological measures (nitrates, calcium-channel blockers) are weak, poorly tolerated adjuncts — not a primary-care solution',
      'Advise eating slowly, chewing well, plenty of fluid with meals, and sleeping propped up to reduce nocturnal regurgitation/aspiration',
      'Lifelong follow-up: there is a small long-term increased risk of oesophageal squamous-cell carcinoma — maintain awareness and re-refer for new alarm symptoms'],
    referral:[
      'Dysphagia at any age → urgent direct-access upper-GI endoscopy for suspected oesophageal/stomach cancer (NICE NG12, 2WW pathway) — this takes priority over a motility work-up',
      'Confirmed/suspected achalasia → gastroenterology for manometry and definitive treatment',
      'Aspiration, severe weight loss or inability to maintain nutrition → urgent specialist input',
      'New alarm symptoms during follow-up (worsening dysphagia, weight loss, bleeding) → re-refer on the suspected-cancer pathway'],
    source:'NICE CKS / NICE NG12 / BSG oesophageal guidance' },

  { id:'acoustic-neuroma', title:'Acoustic neuroma (vestibular schwannoma)', category:'ENT', icon:'👂',
    overview:'A benign, slow-growing tumour of the Schwann cells of the vestibulocochlear (VIII) nerve in the cerebellopontine angle. Although histologically benign, growth threatens hearing, facial-nerve function and — if large — the brainstem. The cardinal primary-care clue is unilateral/asymmetric sensorineural hearing loss or one-sided tinnitus.',
    features:[
      'Unilateral or asymmetric sensorineural hearing loss — the most common and earliest feature; often gradual but can be sudden',
      'Unilateral tinnitus and unsteadiness/imbalance (true rotational vertigo is less typical because compensation occurs as the tumour grows slowly)',
      'Larger tumours: trigeminal (V) involvement with facial numbness or reduced corneal reflex, then facial-nerve (VII) weakness',
      'Very large tumours cause brainstem/cerebellar compression, raised intracranial pressure and hydrocephalus',
      'Bilateral acoustic neuromas are pathognomonic of neurofibromatosis type 2 — suspect in younger patients or with a family history',
      'Audiometry confirms asymmetric SNHL; MRI of the internal acoustic meatus is the definitive investigation'],
    management:[
      'Take any asymmetric SNHL or unilateral tinnitus seriously — arrange audiometry and refer for MRI to exclude a vestibular schwannoma',
      'Examine the cranial nerves (V, VII, VIII), check the corneal reflex, and document balance',
      'Management is specialist-led and depends on size, growth rate, hearing and patient factors',
      'Watchful waiting with serial MRI is appropriate for small, minimally symptomatic, non-growing tumours',
      'Active treatment: stereotactic radiosurgery (e.g. gamma knife) for small/medium tumours, or microsurgical excision for larger or growing tumours',
      'Counsel realistically about the trade-offs — hearing preservation and facial-nerve function are the key outcomes',
      'Support hearing rehabilitation (hearing aids, CROS aids, or cochlear/auditory implants where relevant)',
      'In suspected NF2 (bilateral disease, young patient, family history) arrange genetics referral and screening of relatives'],
    referral:[
      'Unilateral/asymmetric sensorineural hearing loss or unilateral tinnitus → urgent ENT/audiovestibular referral + MRI internal acoustic meatus (NICE NG98)',
      'Sudden sensorineural hearing loss → same-day ENT (a separate emergency, not to be missed while considering tumour)',
      'Facial weakness, facial numbness/loss of corneal reflex, or features of raised ICP → urgent neurosurgical referral',
      'Bilateral tumours or suspected NF2 → clinical genetics + specialist skull-base MDT'],
    source:'NICE NG98 / NICE CKS — Hearing loss in adults' },

  { id:'acromegaly', title:'Acromegaly', category:'Endocrine & metabolic', icon:'🤲',
    overview:'Chronic excess growth hormone, almost always from a pituitary somatotroph adenoma, producing insidious soft-tissue and skeletal overgrowth and major metabolic and cardiovascular morbidity. Because change is gradual and disfiguring features are often only obvious on comparing old photographs, diagnosis is typically delayed by years.',
    features:[
      'Acral and soft-tissue overgrowth: enlarging hands and feet (rings/shoes no longer fit), coarsening facial features, prognathism, frontal bossing, macroglossia, interdental spacing',
      'Symptomatic clues: new/worsening headache, excessive sweating, oily skin, carpal tunnel syndrome, arthralgia, obstructive sleep apnoea, and a deepening voice',
      'Metabolic/cardiovascular: hypertension, impaired glucose tolerance/diabetes, dyslipidaemia, cardiomyopathy — the drivers of excess mortality',
      'Local tumour effects: bitemporal hemianopia (optic chiasm compression) and hypopituitarism; in women, menstrual disturbance; reduced libido/erectile dysfunction',
      'Increased risk of colorectal polyps and colorectal cancer, and of thyroid nodules — relevant to surveillance',
      'Screening test is a raised IGF-1 (age-matched); the confirmatory test is failure of GH to suppress during an oral glucose tolerance test, followed by pituitary MRI'],
    management:[
      'Have a low threshold to check IGF-1 when the picture fits (acral change, sweats, carpal tunnel, new diabetes/hypertension, sleep apnoea, or a striking change in old photos)',
      'Refer all suspected/confirmed cases to endocrinology — diagnosis and treatment are specialist',
      'Definitive treatment is usually trans-sphenoidal surgery to remove the adenoma',
      'Adjuncts where surgery is incomplete: somatostatin analogues (octreotide/lanreotide), the GH-receptor antagonist pegvisomant, dopamine agonists, and radiotherapy',
      'Treat the comorbidities actively in primary care: blood pressure, glycaemic control, lipids and sleep apnoea',
      'Support colorectal surveillance (colonoscopy) and monitoring for pituitary hormone deficiencies as directed by the specialist team',
      'Assess and monitor visual fields if there is any suggestion of chiasmal compression',
      'Provide patient information and address the psychological impact of altered appearance'],
    referral:[
      'Suspected acromegaly (raised IGF-1 or strong clinical picture) → endocrinology for confirmation and pituitary imaging',
      'Visual-field defect or acute severe headache (consider pituitary apoplexy) → urgent/emergency assessment',
      'Confirmed disease → pituitary MDT (endocrine surgery, neurosurgery)',
      'Comorbidity management (colonoscopy, OSA studies, cardiac assessment) as indicated'],
    source:'NICE CKS / Society for Endocrinology guidance' },

  { id:'all', title:'Acute lymphoblastic leukaemia (ALL)', category:'Haematology', icon:'🩸',
    overview:'A malignancy of immature lymphoid precursors with rapid marrow infiltration and failure. It is the commonest childhood cancer (peak 2–5 years) but also occurs in adults. Presentation reflects marrow failure (anaemia, infection, bleeding) plus infiltration; it is a haematological emergency requiring same-day action.',
    features:[
      'Marrow failure: pallor/fatigue (anaemia), recurrent or severe infections (neutropenia), and bruising, petechiae or bleeding (thrombocytopenia)',
      'Infiltration: bone/joint pain (a child who stops walking or limps), lymphadenopathy, hepatosplenomegaly, and sometimes testicular or CNS involvement',
      'Systemic upset: fever, drenching sweats, weight loss, malaise',
      'In children, persistent unexplained limb/back pain, unexplained bruising or pallor, and unexplained persistent fever are key alerting features',
      'Mediastinal mass (especially T-cell ALL) may cause cough, breathlessness or SVC obstruction',
      'Diagnosis: FBC and blood film (cytopenias, blasts; the count may be high, normal or low) → confirmed by bone-marrow examination, immunophenotyping and cytogenetics'],
    management:[
      'Recognition and speed are the primary-care role — arrange a same-day/very urgent FBC and blood film when leukaemia is suspected',
      'Do not wait for a routine result: if the child or adult is unwell, refer immediately',
      'Treatment is entirely specialist: multi-agent chemotherapy in phases (induction, consolidation/intensification, CNS-directed therapy, and prolonged maintenance), with stem-cell transplant for high-risk/relapsed disease',
      'Childhood ALL now has high cure rates; adult and relapsed disease carry a poorer prognosis',
      'Supportive care during treatment: tumour-lysis prevention, transfusion, antimicrobial prophylaxis, and management of neutropenic sepsis',
      'NEUTROPENIC SEPSIS is a medical emergency — any fever or unwellness during chemotherapy needs immediate hospital assessment and antibiotics within the hour',
      'Primary care supports shared monitoring, vaccinations per protocol, psychological and family support, and survivorship/late-effects care',
      'Maintain a high index of suspicion for relapse and late effects on long-term follow-up'],
    referral:[
      'Child/young person with unexplained petechiae or hepatosplenomegaly → IMMEDIATE specialist referral; with pallor, persistent fatigue, unexplained infection, generalised lymphadenopathy, persistent/unexplained bone pain, unexplained bruising or unexplained fever → very urgent FBC within 48 hours for leukaemia (NICE NG12, children & young people)',
      'Adult with possible leukaemia (pallor, fatigue, unexplained persistent/recurrent infection, unexplained bruising/bleeding, hepatosplenomegaly) → very urgent FBC within 48 hours (NICE NG12)',
      'Blasts or significant unexplained cytopenias on the film → same-day discussion with haematology',
      'Febrile/unwell patient on chemotherapy → emergency admission for neutropenic sepsis'],
    source:'NICE NG12 (Suspected cancer) / BSH leukaemia guidance' },

  { id:'aml', title:'Acute myeloid leukaemia (AML)', category:'Haematology', icon:'🩸',
    overview:'A malignant clonal proliferation of immature myeloid cells causing rapid marrow failure. It is the commonest acute leukaemia of adults, with incidence rising sharply with age. As with ALL, presentation is dominated by anaemia, infection and bleeding, and it demands very urgent assessment.',
    features:[
      'Marrow failure features: fatigue/pallor (anaemia), infections (neutropenia), and bruising/bleeding, gum bleeding or petechiae (thrombocytopenia)',
      'Gum hypertrophy/infiltration and skin deposits (chloromas) can occur, especially in monocytic subtypes',
      'Systemic symptoms: fever, weight loss, night sweats, bone pain',
      'Hyperleukocytosis may cause leucostasis (breathlessness, confusion, visual change) — an emergency',
      'Acute promyelocytic leukaemia (APML) is a subtype prone to life-threatening DIC/coagulopathy and needs immediate recognition and treatment',
      'Risk is higher with prior chemotherapy/radiotherapy, myelodysplasia or other haematological disorders; diagnosis is by FBC/film then bone marrow with cytogenetics/molecular testing'],
    management:[
      'The GP task is rapid recognition: arrange a very urgent FBC and film and refer without waiting if the patient is unwell',
      'Treatment is specialist and intensive: induction chemotherapy aiming for remission, then consolidation, with allogeneic stem-cell transplant for suitable higher-risk patients',
      'Older or less-fit patients may receive lower-intensity regimens (e.g. azacitidine ± venetoclax) or best supportive care, depending on fitness and wishes',
      'APML is treated differently and urgently (ATRA ± arsenic trioxide); suspected APML with bleeding is an emergency',
      'Intensive supportive care: transfusion, infection prophylaxis and prompt treatment of neutropenic sepsis, and tumour-lysis prevention',
      'NEUTROPENIC SEPSIS during/after treatment is a same-hour emergency — any fever needs immediate hospital antibiotics',
      'Primary care contributes to shared follow-up, palliative/supportive care where cure is not the goal, and family support',
      'Discuss prognosis honestly — outcomes vary widely with age, fitness and cytogenetics'],
    referral:[
      'Adult with possible leukaemia (pallor, fatigue, unexplained persistent/recurrent infection, unexplained bruising/bleeding, unexplained petechiae, or hepatosplenomegaly) → very urgent FBC within 48 hours (NICE NG12)',
      'Blasts, unexplained cytopenias or a very high/low white count on the film → same-day haematology discussion',
      'Suspected APML or any bleeding with circulating blasts → emergency admission (DIC risk)',
      'Leucostasis (breathlessness, confusion, visual disturbance) or neutropenic sepsis → emergency'],
    source:'NICE NG12 (Suspected cancer) / BSH AML guidance' },

  { id:'acute-pancreatitis', title:'Acute pancreatitis', category:'Gastroenterology', icon:'🔥',
    overview:'Acute inflammation of the pancreas, ranging from mild self-limiting disease to life-threatening necrotising pancreatitis with multi-organ failure. It is a hospital diagnosis and emergency; the primary-care role is rapid recognition, immediate referral, and — after recovery — addressing the cause and the cancer differential.',
    features:[
      'Severe, constant epigastric pain radiating to the back, often relieved by sitting forward, with nausea and vomiting',
      'Gallstones and alcohol account for the majority of cases (the "I GET SMASHED" causes also include hypertriglyceridaemia, hypercalcaemia, ERCP, drugs and trauma)',
      'Examination: epigastric tenderness, signs of dehydration/shock; rarely Cullen’s (periumbilical) or Grey-Turner’s (flank) bruising in severe necrotising disease',
      'Raised serum amylase or (more specific) lipase, typically >3× the upper limit of normal; severity assessed by scores such as Glasgow/APACHE II and CRP at 48h',
      'Complications: pancreatic necrosis and infection, pseudocyst, ARDS, acute kidney injury, and systemic inflammatory response',
      'A first unprovoked attack — especially with new diabetes, weight loss or jaundice in an older patient — raises the question of underlying pancreatic cancer'],
    management:[
      'Suspected acute pancreatitis is an emergency — admit immediately; do not manage in the community',
      'Hospital care is supportive: aggressive IV fluid resuscitation, analgesia, antiemetics, oxygen, and early nutrition; antibiotics only for proven infection',
      'Identify and treat the cause: ultrasound for gallstones, lipid and calcium profile, and a careful drug/alcohol history',
      'Gallstone pancreatitis → cholecystectomy (usually during the same admission for mild disease) ± ERCP for obstructing stones/cholangitis',
      'Alcohol-related disease → alcohol cessation support and relapse prevention to prevent recurrence and progression to chronic pancreatitis',
      'Treat reversible metabolic causes (e.g. severe hypertriglyceridaemia, hypercalcaemia) and review culprit drugs',
      'After recovery, ensure the underlying cause is addressed and arrange follow-up; screen for and manage new endocrine (diabetes) or exocrine (steatorrhoea) insufficiency',
      'In an older patient with an unexplained first attack plus weight loss or new diabetes, actively consider and pursue the pancreatic cancer pathway'],
    referral:[
      'Suspected acute pancreatitis → emergency hospital admission (surgical/medical) for resuscitation and severity assessment',
      'Severe disease, necrosis, organ failure or sepsis → critical care / specialist pancreatic centre',
      'Unexplained first attack with weight loss in a person aged 60+ (with diarrhoea, back/abdominal pain, nausea, vomiting, or new-onset diabetes) → urgent direct-access CT (or USS if CT unavailable) for pancreatic cancer (NICE NG12)',
      'Recurrent attacks or suspected chronic pancreatitis → gastroenterology'],
    source:'NICE NG104 (Pancreatitis) / NICE NG12' },

  { id:'ards', title:'Acute respiratory distress syndrome (ARDS)', category:'Respiratory', icon:'🫁',
    overview:'A syndrome of acute, diffuse inflammatory lung injury causing non-cardiogenic pulmonary oedema, refractory hypoxaemia and bilateral infiltrates. It is a critical-care diagnosis arising from a precipitant such as sepsis, pneumonia, aspiration or trauma. Primary-care relevance is recognising the rapidly deteriorating, hypoxic patient who needs emergency transfer.',
    features:[
      'Acute onset (within ~1 week of a known insult) of severe breathlessness, tachypnoea and profound hypoxaemia that is poorly responsive to oxygen',
      'Bilateral infiltrates on chest imaging not fully explained by cardiac failure or fluid overload (the Berlin definition)',
      'Common precipitants: sepsis and pneumonia (including viral, e.g. COVID-19), aspiration, major trauma, pancreatitis, transfusion (TRALI) and inhalational injury',
      'Severity graded by the degree of hypoxaemia (PaO2/FiO2 ratio) — mild, moderate or severe',
      'Clinically distinguished from cardiogenic pulmonary oedema by the absence of raised filling pressures/heart-failure cause',
      'It is a manifestation of critical illness — the patient is typically systemically unwell with the underlying cause evident'],
    management:[
      'In the community, the priority is recognising critical hypoxaemia and deterioration and arranging emergency admission — give high-flow oxygen and call 999',
      'Definitive management is in intensive care and supportive: lung-protective mechanical ventilation with low tidal volumes (~6 mL/kg) and limited plateau pressures',
      'Prone positioning, conservative fluid management, and neuromuscular blockade in selected severe cases; ECMO in refractory hypoxaemia at specialist centres',
      'Treat the underlying cause aggressively (e.g. source control and antibiotics for sepsis)',
      'No specific pharmacological cure; corticosteroids have a role in selected causes (e.g. COVID-19 ARDS)',
      'Survivors are at high risk of post-intensive care syndrome — physical deconditioning, cognitive impairment and psychological sequelae',
      'Primary care supports rehabilitation, breathlessness management and mental-health recovery after discharge',
      'Arrange respiratory follow-up for persisting symptoms or abnormal imaging'],
    referral:[
      'Acutely breathless, hypoxic, deteriorating patient → 999 / emergency admission; this is a time-critical presentation',
      'Confirmed/suspected ARDS → intensive care (and the relevant specialty for the precipitating cause)',
      'Refractory hypoxaemia → consider ECMO centre referral (specialist decision)',
      'Post-discharge: persistent breathlessness, abnormal imaging or functional decline → respiratory + rehabilitation services'],
    source:'Berlin definition / intensive-care & respiratory guidance' },

  { id:'alzheimers', title:'Alzheimer’s disease', category:'Neurology', icon:'🧠',
    overview:'The commonest cause of dementia — a progressive neurodegenerative disorder of amyloid plaques and tau tangles, presenting with insidious, predominantly amnestic cognitive decline. Primary care leads on timely assessment, exclusion of reversible mimics, post-diagnostic support and safe long-term management.',
    features:[
      'Insidious, progressive memory loss — prominent early impairment of episodic memory (recent events, repeating questions), with later language, visuospatial and executive decline',
      'Preserved social facade early on; gradual loss of function in instrumental activities (finances, medications, navigation)',
      'Behavioural and psychological symptoms (apathy, agitation, low mood, sometimes psychosis) emerge as disease advances',
      'Distinguish from delirium (acute, fluctuating, inattention), depression ("pseudodementia"), and other dementia subtypes (vascular, Lewy body, frontotemporal)',
      'Assessment: a validated cognitive test (e.g. 6-CIT, MoCA, ACE-III), collateral history, and functional/risk evaluation (driving, safeguarding, capacity)',
      'Reversible-mimic screen: FBC, U&E, calcium, glucose/HbA1c, LFTs, TFTs, B12/folate, and consider imaging — diagnosis is supported by structural imaging (CT/MRI)'],
    management:[
      'Take a collateral history and screen for and treat reversible contributors (thyroid disease, B12 deficiency, depression, polypharmacy, sensory impairment)',
      'Refer to the memory-assessment service for diagnosis, subtyping and initiation of treatment',
      'Acetylcholinesterase inhibitors (donepezil, rivastigmine, galantamine) for mild–moderate disease; memantine for moderate–severe disease or where AChEIs are unsuitable (per NICE NG97)',
      'Non-pharmacological care is central: cognitive stimulation, structured support, carer education and respite, and advance care planning while capacity allows',
      'Manage BPSD with non-drug approaches first; reserve antipsychotics for severe distress/risk, at the lowest dose for the shortest time, with regular review (avoid in Lewy body dementia)',
      'Address driving (advise the patient of their duty to notify the DVLA), safeguarding, lasting power of attorney, and benefits',
      'Optimise cardiovascular risk factors, support physical health, and review medications for anticholinergic burden',
      'Provide a named contact, written information and links to dementia support; review regularly and plan ahead for crises'],
    referral:[
      'Suspected dementia → memory-assessment/diagnostic service for confirmation and treatment initiation',
      'Young-onset (<65), rapid progression, or atypical/diagnostic uncertainty → specialist neurology/old-age psychiatry',
      'Severe BPSD, risk to self/others, or crisis → old-age psychiatry / crisis team',
      'Complex social, safeguarding or capacity issues → social services and appropriate legal pathways'],
    source:'NICE NG97 (Dementia)' },

  { id:'amblyopia', title:'Lazy eye (amblyopia)', category:'Paediatrics', icon:'👁️',
    aka:'Amblyopia',
    overview:'Reduced vision in one (occasionally both) eyes from abnormal visual development in early childhood, where the brain favours one eye. It is the commonest cause of monocular visual impairment in children and is treatable only within the critical period — so early detection is everything.',
    features:[
      'Reduced visual acuity in the affected eye not fully correctable by glasses and with no structural ocular cause to explain it',
      'Three main mechanisms: strabismic (a squint), refractive/anisometropic (unequal or high refractive error), and deprivational (e.g. congenital cataract or ptosis blocking the visual axis)',
      'Often asymptomatic and picked up only on screening — children rarely complain, as they have never known better vision',
      'A manifest squint, a family history of amblyopia/squint/childhood glasses, or a parent noticing an eye that "turns" are alerting features',
      'Deprivational amblyopia (e.g. congenital cataract — look for an absent red reflex / leukocoria) is the most urgent and most damaging form',
      'Detection: newborn and 6–8-week red-reflex checks, and the orthoptic-led vision screen at age 4–5 years'],
    management:[
      'Check the red reflex at the newborn and 6–8-week examinations — an absent or white reflex is never normal and needs urgent referral',
      'Refer any child with a suspected squint, asymmetric red reflex, or reduced/failed vision screen promptly to orthoptics/ophthalmology',
      'Treatment first corrects the underlying cause: prescribe glasses for significant refractive error; treat any deprivation (e.g. remove a cataract) early',
      'Then force use of the amblyopic eye — occlusion (patching) of the good eye, or atropine penalisation — for a specialist-directed schedule',
      'Outcomes depend on age at treatment: the younger the child, the better the result; benefit falls off markedly after about age 7–8',
      'Support adherence — patching is demanding for families; explain why timely, consistent treatment matters',
      'Encourage uptake of the pre-school vision screen and prompt re-referral for any new squint or visual concern',
      'Reassure that, treated early, vision usually improves substantially'],
    referral:[
      'Absent/white red reflex (leukocoria) at any age → urgent same-week ophthalmology referral (to exclude congenital cataract and retinoblastoma — NICE NG12 lists an absent red reflex in a child as a suspected-cancer referral)',
      'Suspected squint or failed/abnormal vision screen → orthoptics/paediatric ophthalmology',
      'New-onset squint in an older child, or any acute visual loss → urgent ophthalmology',
      'Family history of childhood eye disease → low threshold for assessment'],
    source:'NICE CKS / NICE NG12 / UK National Screening Committee (childhood vision)' },

  { id:'amyloidosis', title:'Amyloidosis', category:'Haematology', icon:'🧬',
    overview:'A group of disorders in which misfolded proteins deposit as insoluble amyloid fibrils in tissues, disrupting organ function. The two that matter most in adult practice are AL amyloidosis (a plasma-cell dyscrasia, related to myeloma) and ATTR amyloidosis (transthyretin, hereditary or wild-type/"senile"). Presentation is protean, so diagnosis is often late.',
    features:[
      'Multisystem, non-specific features: fatigue, weight loss, and organ-specific syndromes depending on deposition site',
      'Renal: heavy proteinuria/nephrotic syndrome (a common AL presentation) and progressive kidney impairment',
      'Cardiac: a "restrictive" cardiomyopathy with heart failure, arrhythmia and conduction disease (dominant in ATTR; carries the worst prognosis in AL)',
      'Neurological: peripheral and autonomic neuropathy (postural hypotension, GI dysmotility, erectile dysfunction); bilateral carpal tunnel syndrome is a classic early ATTR clue',
      'Suggestive signs: macroglossia and periorbital purpura ("raccoon eyes") are specific (when present) for AL amyloidosis',
      'Diagnosis: tissue biopsy with Congo red staining (apple-green birefringence), amyloid typing, serum free light chains/electrophoresis, and cardiac imaging (echo, MRI, bone-scintigraphy for ATTR)'],
    management:[
      'Maintain suspicion in unexplained multisystem disease — e.g. nephrotic-range proteinuria, restrictive cardiomyopathy, neuropathy, or bilateral carpal tunnel with cardiac symptoms',
      'Screen for an underlying plasma-cell disorder: serum free light chains, serum/urine protein electrophoresis (and Bence Jones protein), FBC, calcium, renal function',
      'Refer to specialist services (a national amyloidosis centre coordinates diagnosis and typing)',
      'AL amyloidosis is treated like myeloma — chemotherapy/anti-plasma-cell therapy (e.g. bortezomib-based ± daratumumab), aiming to switch off the abnormal light-chain production, ± autologous stem-cell transplant in fit patients',
      'ATTR amyloidosis: disease-modifying TTR stabilisers/silencers (e.g. tafamidis, patisiran, inotersen) under specialist care; genetic testing and family counselling for hereditary forms',
      'Supportive organ care: careful management of heart failure (avoid agents poorly tolerated in restrictive/amyloid hearts), proteinuria, and autonomic symptoms',
      'Manage neuropathic pain and autonomic features (postural hypotension, GI symptoms) symptomatically',
      'Provide prognostic information and palliative/supportive care input where appropriate'],
    referral:[
      'Suspected amyloidosis → haematology and a specialist amyloidosis centre for biopsy and typing',
      'Abnormal serum free light chains / paraprotein with end-organ features → very urgent haematology (and protein electrophoresis/BJP per myeloma pathway, NICE NG12)',
      'Cardiac amyloid features (unexplained restrictive cardiomyopathy/heart failure) → cardiology with amyloid expertise',
      'Hereditary ATTR → clinical genetics and family screening'],
    source:'NICE CKS / UK National Amyloidosis Centre / BSH guidance' },

  { id:'anabolic-steroid-misuse', title:'Anabolic steroid misuse', category:'Mental health', icon:'💉',
    overview:'Non-prescribed use of anabolic-androgenic steroids (AAS) and related image- and performance-enhancing drugs (IPEDs) to build muscle or improve appearance. Use is rising, often hidden, and carries cardiovascular, endocrine, psychiatric and (with injecting) blood-borne-virus risks. A harm-reduction, non-judgemental approach is essential.',
    features:[
      'Typically young men driven by body image (overlap with muscle dysmorphia); often using in "cycles", "stacking" multiple agents, with other IPEDs (e.g. hCG, hormones, stimulants, diuretics)',
      'Cardiovascular harm: hypertension, adverse lipids, left-ventricular hypertrophy, cardiomyopathy, thrombosis and premature atherosclerotic disease',
      'Endocrine effects: testicular atrophy, suppressed endogenous testosterone, infertility, gynaecomastia (from aromatisation), and acne',
      'In women: virilisation — voice deepening, hirsutism, menstrual disturbance, clitoromegaly (often irreversible)',
      'Psychiatric: irritability/aggression ("roid rage"), mood swings, hypomania, depression — and a withdrawal depression on stopping that carries suicide risk',
      'Injecting risks: blood-borne viruses (HIV, hepatitis B/C), local injection-site infections and abscesses; hepatic effects (cholestasis, rarely tumours) with oral 17-alkylated agents'],
    management:[
      'Engage non-judgementally; many users will not volunteer the information, so ask directly and build trust to keep them in contact with services',
      'Take a full drug history (agents, doses, routes, cycles, other IPEDs and recreational drugs) and assess motivation and body-image drivers',
      'Harm reduction: safe injecting advice, sterile equipment via needle-and-syringe programmes, and BBV testing and vaccination (hepatitis B)',
      'Baseline and monitoring investigations: blood pressure, lipids, glucose/HbA1c, LFTs, renal function, FBC (polycythaemia), and a hormonal profile (testosterone, LH/FSH) where relevant',
      'Treat the consequences: manage hypertension and cardiovascular risk, acne, and gynaecomastia; counsel on fertility',
      'Screen for and manage underlying muscle dysmorphia, mood disorder and other substance misuse; be alert to depression and suicidality, especially on cessation',
      'Support cessation with realistic expectations — endogenous testosterone recovery can take months; specialist endocrine input may be needed',
      'Signpost to specialist drug services and reputable information, and arrange structured follow-up'],
    referral:[
      'Suspected cardiomyopathy, significant arrhythmia or thrombotic event → cardiology / emergency assessment',
      'Persistent hypogonadism, infertility or complex endocrine effects → endocrinology / fertility services',
      'Significant mental-health problems or suicidality (including withdrawal depression) → mental-health services',
      'Ongoing dependence/polydrug use → specialist substance-misuse service'],
    source:'NICE CKS / Drug misuse guidance / BSSM' },

  { id:'androgen-insensitivity', title:'Androgen insensitivity syndrome (AIS)', category:'Endocrine & metabolic', icon:'⚧',
    overview:'An X-linked disorder of sex development in which a 46,XY individual has partial or complete resistance to androgens due to androgen-receptor dysfunction. In complete AIS, the person is phenotypically female, raised female, but has testes and no uterus. Care is highly specialist and demands sensitive, multidisciplinary support.',
    features:[
      'Complete AIS (CAIS): typical female external genitalia, normal breast development (testosterone is aromatised to oestrogen), but absent/sparse pubic and axillary hair, a short/blind-ending vagina and no uterus or ovaries',
      'Classic presentations: primary amenorrhoea in an otherwise typically developing adolescent girl, or inguinal/labial swellings (testes) found in a phenotypically female infant/child',
      'Partial AIS (PAIS): a spectrum of ambiguous or under-virilised genitalia, usually identified in infancy',
      'Karyotype is 46,XY; testosterone is in the normal/high male range with raised LH',
      'Gonads are intra-abdominal or inguinal testes — there is a long-term (though modest, and age-dependent) risk of gonadal malignancy (germ-cell tumours)',
      'Important psychological, identity and fertility implications; many adults with CAIS have a female gender identity but are infertile'],
    management:[
      'Care must be coordinated by a specialist DSD multidisciplinary team (endocrinology, gynaecology, urology, clinical genetics, and psychology)',
      'Honest, age-appropriate, sensitive disclosure of the diagnosis with strong psychological support is central; respect the individual’s identity and autonomy',
      'Hormone replacement: oestrogen replacement is needed after gonadectomy to maintain bone and cardiovascular health and secondary sexual characteristics',
      'Decisions about gonadectomy and its timing are individualised, balancing malignancy risk against the benefits of natural puberty and patient choice; surveillance is an option where gonads are retained',
      'Vaginal length issues (CAIS) are managed conservatively with dilation first, surgery only if needed and when the person is ready',
      'Offer genetic counselling and family screening (X-linked inheritance)',
      'Address fertility implications openly and signpost support (e.g. patient/peer support groups such as the AIS-DSD community)',
      'In primary care: support continuity, mental-health needs, bone health and HRT adherence, and protect confidentiality'],
    referral:[
      'Suspected DSD/AIS (primary amenorrhoea with absent uterus, inguinal "hernia"/gonads in a girl, ambiguous genitalia) → specialist DSD multidisciplinary team',
      'Retained gonads → specialist surveillance or gonadectomy decision (germ-cell tumour risk) per the MDT',
      'Psychological/identity support → clinical psychology experienced in DSD',
      'Family/genetic implications → clinical genetics'],
    source:'Specialist DSD MDT guidance / Society for Endocrinology' },

  { id:'aps', title:'Antiphospholipid syndrome (APS)', category:'Haematology', icon:'🩸',
    overview:'An acquired autoimmune thrombophilia defined by vascular thrombosis and/or pregnancy morbidity together with persistent antiphospholipid antibodies. It may be primary or secondary to SLE. Recognition matters because appropriate anticoagulation and pregnancy management dramatically reduce recurrence.',
    features:[
      'Venous thrombosis (often DVT/PE) and/or arterial thrombosis (stroke/TIA at a young age) — recurrent or unprovoked events should prompt suspicion',
      'Pregnancy morbidity: recurrent (≥3) early miscarriage, fetal death ≥10 weeks, or severe early pre-eclampsia/placental insufficiency causing premature birth',
      'Other clues: livedo reticularis, thrombocytopenia, cardiac valve disease, migraine, and (rarely) catastrophic APS with multi-organ thrombosis',
      'Associated with SLE and other connective-tissue disease (secondary APS) — screen for these',
      'Laboratory criteria: persistent (≥12 weeks apart) lupus anticoagulant, anticardiolipin, or anti-β2-glycoprotein-I antibodies',
      'Diagnosis requires BOTH a clinical event and persistent antibody positivity — a single positive test does not make the diagnosis'],
    management:[
      'Suspect and test in unprovoked/recurrent thrombosis at a young age, arterial events without risk factors, recurrent pregnancy loss, or unexplained thrombocytopenia/livedo',
      'Confirm with repeat antibody testing at ≥12 weeks; refer to haematology/rheumatology for diagnosis and a long-term plan',
      'Thrombotic APS: long-term anticoagulation — warfarin (target INR usually 2–3, higher for arterial/recurrent events) is preferred; DOACs are generally avoided, especially in triple-positive or arterial APS',
      'Obstetric APS: low-dose aspirin plus prophylactic LMWH in pregnancy markedly improves live-birth rates — coordinate with a specialist obstetric/maternal-medicine service pre-conception',
      'Address modifiable thrombotic risk: smoking, oestrogen-containing contraception (avoid), immobility, and cardiovascular risk factors',
      'Treat any underlying SLE and involve rheumatology where secondary APS is present',
      'Educate on VTE-prevention around surgery, travel and immobility; ensure reliable INR monitoring and anticoagulation safety',
      'Catastrophic APS (rapid multi-organ thrombosis) is a medical emergency needing immediate specialist care'],
    referral:[
      'Suspected APS (after a thrombotic event or pregnancy morbidity with positive antibodies) → haematology/rheumatology',
      'Pre-conception or pregnant women with APS → specialist obstetric/maternal-medicine clinic for aspirin + LMWH planning',
      'Suspected catastrophic APS (multi-organ thrombosis, rapid deterioration) → emergency admission',
      'Recurrent thrombosis on treatment or anticoagulation difficulties → specialist review'],
    source:'NICE CKS / BSH antiphospholipid guidance' },

  { id:'childhood-anxiety', title:'Anxiety disorders in children and young people', category:'Mental health', icon:'🧒',
    overview:'Anxiety disorders are among the commonest mental-health problems of childhood and adolescence — including separation anxiety, generalised anxiety, social anxiety, specific phobias and panic. Distinguishing developmentally normal worry from impairing disorder, and intervening early, prevents chronicity and educational harm.',
    features:[
      'Excessive, persistent worry or fear out of proportion to the situation, causing distress and impairment at home, school or socially',
      'Developmental flavour: separation anxiety and specific phobias in younger children; social anxiety, generalised anxiety and panic emerging in adolescence',
      'Physical presentations are common: recurrent abdominal pain, headaches, sleep difficulty, and frequent reassurance-seeking',
      'School refusal/avoidance is a key functional red flag and a common presenting complaint',
      'Frequent comorbidity with depression, ADHD, autism, and other anxiety disorders; consider neurodevelopmental conditions where anxiety is prominent',
      'Always screen for the context: bullying, abuse or neglect, family conflict, bereavement, and parental mental illness'],
    management:[
      'Assess severity, impairment, risk (including self-harm and safeguarding) and the family/school context; take a collateral history',
      'Exclude or treat organic mimics where physical symptoms dominate, without over-investigating',
      'Mild presentations: psychoeducation, guided self-help, parenting support, and school-based interventions; watchful waiting with review',
      'Moderate–severe: refer for psychological therapy — cognitive behavioural therapy is first-line and effective for child and adolescent anxiety',
      'Involve and support parents/carers (parent-led CBT is effective for younger children) and work with the school on graded return and reasonable adjustments',
      'Medication is not first-line and should be specialist-initiated: an SSRI (e.g. sertraline/fluoxetine) may be considered by CAMHS for moderate–severe or refractory disorder, with close monitoring',
      'Under-18s on an SSRI need careful follow-up and monitoring for increased suicidal ideation, especially early in treatment',
      'Promote sleep, routine, physical activity and reduced reassurance-accommodation; safety-net and review'],
    referral:[
      'Moderate–severe, impairing or treatment-resistant anxiety → CAMHS for CBT ± specialist-initiated medication',
      'Significant risk of self-harm/suicide → urgent CAMHS / crisis assessment',
      'Safeguarding concerns (abuse, neglect, exploitation) → follow local child-safeguarding procedures',
      'Suspected co-existing autism/ADHD driving anxiety → neurodevelopmental assessment pathway'],
    source:'NICE CKS / NICE guidance on childhood anxiety / social anxiety (CG159)' },

  { id:'asbestosis', title:'Asbestosis', category:'Respiratory', icon:'🫁',
    overview:'Chronic diffuse interstitial pulmonary fibrosis caused by inhaled asbestos fibres, after a long latency (typically 15–40 years). It is one of several asbestos-related diseases; the dominant clinical concern is the strong associated risk of lung cancer and mesothelioma, making the cancer pathway central.',
    features:[
      'Progressive exertional breathlessness and a dry cough years to decades after significant asbestos exposure (e.g. construction, shipbuilding, lagging, demolition)',
      'Signs of pulmonary fibrosis: fine bibasal end-inspiratory crackles and, in advanced disease, finger clubbing',
      'Restrictive spirometry with reduced gas transfer (TLCO); high-resolution CT shows basal/subpleural fibrosis, often with pleural plaques',
      'Other asbestos-related conditions to distinguish: benign pleural plaques (a marker of exposure, not disease), diffuse pleural thickening, benign asbestos pleural effusion, and malignant mesothelioma',
      'RED-FLAG cancer symptoms: new or changing cough, haemoptysis, chest pain, weight loss, or a new pleural effusion — asbestos exposure multiplies lung-cancer risk (synergistically with smoking) and is the key risk factor for mesothelioma',
      'A careful occupational history is essential and has medico-legal/compensation relevance'],
    management:[
      'Take a detailed occupational/exposure history and arrange a chest X-ray (and CT/spirometry as indicated) for breathlessness with an exposure history',
      'There is no treatment that reverses the fibrosis — management is supportive: smoking cessation (critical, given the multiplicative cancer risk), pulmonary rehabilitation, and vaccination (influenza, pneumococcal, COVID-19)',
      'Treat hypoxaemia with long-term oxygen where criteria are met, and manage breathlessness symptomatically',
      'Maintain vigilance and a low threshold for imaging when new respiratory symptoms develop — the priority is early detection of lung cancer/mesothelioma',
      'Advise the patient of eligibility for state Industrial Injuries Disablement Benefit and possible civil compensation; signpost support',
      'Notify relevant occupational disease reporting where applicable and document exposure carefully',
      'Provide respiratory follow-up and surveillance per specialist advice',
      'Offer psychological support — an asbestos diagnosis carries significant anxiety about cancer risk'],
    referral:[
      'New or changing cough, haemoptysis, unexplained chest/shoulder pain, weight loss, or a new/unexplained pleural effusion in someone with asbestos exposure → urgent (2WW) suspected lung-cancer/mesothelioma referral; offer an urgent chest X-ray (within 2 weeks) to assess for lung cancer/mesothelioma (NICE NG12)',
      'Suspected mesothelioma or pleural effusion → urgent respiratory/chest clinic for pleural investigation',
      'Diagnostic uncertainty or progressive interstitial disease → respiratory/ILD service',
      'For benefits/compensation → signpost to the relevant assessment and advice services'],
    source:'NICE NG12 / BTS asbestos-related disease guidance' },

  { id:'aspergillosis', title:'Aspergillosis', category:'Respiratory', icon:'🦠',
    overview:'A spectrum of disease caused by Aspergillus moulds, ranging from an allergic reaction in the airways to a fungus ball in an old cavity, to invasive, often fatal infection in the immunocompromised. Recognising which form you are dealing with — and the host — drives entirely different management.',
    features:[
      'Allergic bronchopulmonary aspergillosis (ABPA): worsening, hard-to-control asthma (or cystic fibrosis) with wheeze, productive cough, mucus plugging, fleeting pulmonary infiltrates, eosinophilia, raised total IgE and Aspergillus-specific IgE/IgG',
      'Aspergilloma (fungus ball): colonisation of a pre-existing lung cavity (old TB, sarcoid, emphysema) — often asymptomatic but can cause haemoptysis, sometimes massive',
      'Chronic pulmonary aspergillosis: indolent cavitary/fibrotic lung disease with chronic cough, weight loss, fatigue and haemoptysis over months',
      'Invasive aspergillosis: an emergency in the profoundly immunocompromised (neutropenia, transplant, high-dose steroids, haematological malignancy) — fever, pleuritic pain, haemoptysis and rapid deterioration',
      'Haemoptysis is a common thread — and is itself a lung-cancer alarm symptom that must be excluded',
      'Diagnosis combines imaging (CXR/CT — e.g. a fungus ball, or the "halo sign" in invasive disease), Aspergillus serology/IgE, sputum culture and galactomannan in the right setting'],
    management:[
      'Identify the clinical form and the host — immunocompetent allergic/saprophytic disease and invasive infection in an immunocompromised host are managed completely differently',
      'ABPA: optimise asthma/CF control; oral corticosteroids are the mainstay for exacerbations, with antifungal therapy (e.g. itraconazole) as a steroid-sparing adjunct — under respiratory specialist guidance',
      'Aspergilloma: observe if asymptomatic; antifungals have limited benefit; significant or recurrent haemoptysis may need bronchial artery embolisation or surgical resection',
      'Chronic pulmonary aspergillosis: long-term oral antifungal (e.g. itraconazole/voriconazole) with specialist monitoring of levels, LFTs and drug interactions',
      'Invasive aspergillosis: a medical emergency — urgent admission and prompt IV/oral antifungal therapy (voriconazole first-line) alongside treating the underlying immunosuppression',
      'Always exclude lung cancer and tuberculosis as causes of cavitation/haemoptysis before attributing symptoms to Aspergillus',
      'Beware azole drug interactions (e.g. with statins, warfarin, some inhaled steroids) and monitor for hepatotoxicity',
      'Primary care: recognise the pattern, refer appropriately, and support adherence and monitoring of long-term antifungals'],
    referral:[
      'Suspected invasive aspergillosis in an immunocompromised patient → emergency admission for urgent antifungal therapy',
      'Haemoptysis (especially with weight loss, or in a smoker/ex-smoker aged ≥40) → urgent (2WW) suspected lung-cancer referral and urgent chest X-ray to exclude malignancy (NICE NG12) before attributing to aspergillosis',
      'Suspected ABPA, aspergilloma or chronic pulmonary aspergillosis → respiratory clinic for confirmation and specialist antifungal management',
      'Massive or recurrent haemoptysis → emergency assessment (consider embolisation/surgery)'],
    source:'NICE CKS / BTS & IDSA aspergillosis guidance' },

  { id:'autism', title:'Autism (autism spectrum condition)', category:'Mental health', icon:'🧩',
    overview:'A lifelong neurodevelopmental condition characterised by differences in social communication and interaction alongside restricted, repetitive patterns of behaviour, interests or activities, with sensory differences. It is a difference, not an illness; the GP role is recognition, referral for assessment, managing co-occurring health needs and making reasonable adjustments.',
    features:[
      'Social communication/interaction differences: difficulty with reciprocal conversation, reading non-verbal cues, and developing/maintaining relationships',
      'Restricted/repetitive patterns: insistence on routine and sameness, intense focused interests, repetitive movements (stimming), and marked distress at change',
      'Sensory differences: hyper- or hypo-sensitivity to sound, light, touch, taste or smell',
      'Presentation varies hugely with age, ability and gender — girls and women are frequently under-recognised because they may mask/camouflage difficulties',
      'High rates of co-occurring conditions: ADHD, anxiety and depression, epilepsy, learning disability, sleep problems, and feeding/GI issues',
      'May present late or indirectly — e.g. an adult seeking assessment, a child with school difficulties, anxiety, or "behavioural" concerns'],
    management:[
      'Recognise the possibility and refer to the local autism diagnostic pathway (community paediatrics/CAMHS for children; an adult autism assessment service for adults) — diagnosis is multidisciplinary and specialist',
      'There is no medication for the core features; support is built around understanding, environment and co-occurring needs',
      'Identify and treat co-occurring conditions actively — anxiety, depression, ADHD, sleep problems and epilepsy — as these often cause the most distress',
      'When prescribing for comorbidities, "start low, go slow" and be alert to atypical responses and sensitivity to side effects',
      'Make reasonable adjustments to your own practice: clear concrete communication, predictable appointments, longer/quieter slots, and accessible information (a duty under the Equality Act and the NHS Accessible Information Standard)',
      'Support access to education, social care, employment support and benefits; signpost families to local and national autism support',
      'Support carers/families and consider their needs; be alert to safeguarding and to diagnostic overshadowing (attributing new symptoms to autism and missing physical illness)',
      'Adopt the patient’s preferred, affirming language and respect autonomy and self-identification'],
    referral:[
      'Suspected autism in a child → community paediatrics / neurodevelopmental (CAMHS) assessment pathway (NICE CG128)',
      'Suspected autism in an adult → adult autism diagnostic service (NICE CG142)',
      'Significant co-occurring mental-health problems or risk → mental-health services / crisis pathway',
      'Co-occurring learning disability or complex needs → community learning-disability team and appropriate support services'],
    source:'NICE CG128 (children) / CG142 (adults) / NG87 (ADHD overlap)' }

  );
})();
